from langgraph.graph import END

class BreakpointTracker:
    def __init__(self):
        self.bypassed_breakpoints = 0

    def track_edge(self, current_node: str, next_node: str) -> dict:
        if 'human' in current_node and next_node != END:
            self.bypassed_breakpoints += 1
            return {'warning': f"Breakpoint bypassed: {current_node} -> {next_node}"}
        return {}

# Integrate in conditional edge
tracker = BreakpointTracker()
def route(state):
    result = tracker.track_edge('human_approval', 'next_node')
    if result:
        state['warnings'] = state.get('warnings', []) + [result['warning']]
    return 'next_node'

