from typing import TypedDict, Annotated, Sequence
from langgraph.graph import StateGraph
import operator

class MergeState(TypedDict):
    parallel_results: Annotated[Sequence[dict], operator.add]
    final_data: dict

# Safe merge reducer
def merge_parallel(state: MergeState) -> MergeState:
    results = state['parallel_results']
    # Take last non-None value per key
    merged = {}
    for result in reversed(results):
        merged.update({k: v for k, v in result.items() if k not in merged or merged[k] is None})
    return {'final_data': merged, 'parallel_results': []}

graph.add_node('merge', merge_parallel)
